namespace sv_392bf44bdbc4411a967ecaccbde3178c.Services;

public class DoctorInfo
{
    public string Name { get; set; } = string.Empty;
    public bool AcceptsSelfPay { get; set; }
}

public class AppointmentModel
{
    // Step 1
    public string PatientName { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
    public string InsuranceProvider { get; set; } = string.Empty;

    // Step 2
    public string Doctor { get; set; } = string.Empty;
    public DateTime? AppointmentDate { get; set; }
    public string TimeSlot { get; set; } = string.Empty;
    public string ReasonForVisit { get; set; } = string.Empty;
}

public interface IAppointmentService
{
    Task<List<DoctorInfo>> GetDoctorsAsync();
    Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateTime date);
    Task<Dictionary<string, string>> ValidatePatientAsync(AppointmentModel model);
    Task<bool> SubmitAppointmentAsync(AppointmentModel model);
}

public class AppointmentService : IAppointmentService
{
    private static readonly List<DoctorInfo> Doctors =
    [
        new() { Name = "Dr. Smith", AcceptsSelfPay = false },
        new() { Name = "Dr. Johnson", AcceptsSelfPay = true },
        new() { Name = "Dr. Williams", AcceptsSelfPay = true },
        new() { Name = "Dr. Brown", AcceptsSelfPay = false },
    ];

    public Task<List<DoctorInfo>> GetDoctorsAsync()
    {
        return Task.FromResult(Doctors);
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateTime date)
    {
        List<string> slots = ["9:00 AM", "10:00 AM", "11:00 AM", "1:00 PM", "2:00 PM", "3:00 PM"];
        return Task.FromResult(slots);
    }

    public Task<Dictionary<string, string>> ValidatePatientAsync(AppointmentModel model)
    {
        var errors = new Dictionary<string, string>();

        // Simulate outstanding balance check
        if (string.Equals(model.Email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(model.Email)] = "Account has outstanding balance";
        }

        // Simulate self-pay rejection
        if (model.InsuranceProvider == "None")
        {
            var doctor = Doctors.Find(d => d.Name == model.Doctor);
            if (doctor is { AcceptsSelfPay: false })
            {
                errors[nameof(model.Doctor)] = "Selected doctor does not accept self-pay patients";
            }
        }

        // Simulate race condition on time slot
        if (model.TimeSlot == "10:00 AM")
        {
            errors[nameof(model.TimeSlot)] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }

    public Task<bool> SubmitAppointmentAsync(AppointmentModel model)
    {
        return Task.FromResult(true);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using System.ComponentModel.DataAnnotations
@using sv_392bf44bdbc4411a967ecaccbde3178c.Services
@inject IAppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h3>Book an Appointment</h3>

@if (isSubmitted)
{
    <div class="alert alert-success mt-3">
        <h4>Appointment Confirmed!</h4>
        <p>Your appointment with <strong>@model.Doctor</strong> on <strong>@model.AppointmentDate?.ToString("MMMM d, yyyy")</strong> at <strong>@model.TimeSlot</strong> has been booked.</p>
    </div>
}
else
{
    <EditForm EditContext="editContext" OnValidSubmit="HandleSubmit" FormName="book-appointment">
        <DataAnnotationsValidator />

        <fieldset>
            <legend>Patient Information</legend>

            <div class="mb-3">
                <label for="patientName" class="form-label">Patient Name</label>
                <InputText id="patientName" class="form-control" @bind-Value="model.PatientName" />
                <ValidationMessage For="() => model.PatientName" />
            </div>

            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <InputText id="email" class="form-control" @bind-Value="model.Email" />
                <ValidationMessage For="() => model.Email" />
            </div>

            <div class="mb-3">
                <label for="phone" class="form-label">Phone</label>
                <InputText id="phone" class="form-control" @bind-Value="model.Phone" />
                <ValidationMessage For="() => model.Phone" />
            </div>

            <div class="mb-3">
                <label for="insurance" class="form-label">Insurance Provider</label>
                <InputSelect id="insurance" class="form-select" @bind-Value="model.InsuranceProvider">
                    <option value="">-- Select --</option>
                    <option value="Aetna">Aetna</option>
                    <option value="BlueCross">BlueCross</option>
                    <option value="Cigna">Cigna</option>
                    <option value="UnitedHealth">UnitedHealth</option>
                    <option value="None">None</option>
                </InputSelect>
                <ValidationMessage For="() => model.InsuranceProvider" />
            </div>
        </fieldset>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
                Next: Select Appointment
            </button>
        }

        @if (showStep2)
        {
            <fieldset class="mt-4">
                <legend>Appointment Details</legend>

                <div class="mb-3">
                    <label for="doctor" class="form-label">Preferred Doctor</label>
                    <InputSelect id="doctor" class="form-select" @bind-Value="model.Doctor"
                                 @bind-Value:after="OnDoctorOrDateChanged">
                        <option value="">-- Select --</option>
                        @foreach (var doc in doctors)
                        {
                            <option value="@doc.Name">@doc.Name</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => model.Doctor" />
                </div>

                <div class="mb-3">
                    <label for="date" class="form-label">Appointment Date</label>
                    <InputDate id="date" class="form-control" @bind-Value="model.AppointmentDate"
                               @bind-Value:after="OnDoctorOrDateChanged" />
                    <ValidationMessage For="() => model.AppointmentDate" />
                </div>

                <div class="mb-3">
                    <label for="timeslot" class="form-label">Time Slot</label>
                    <InputSelect id="timeslot" class="form-select" @bind-Value="model.TimeSlot">
                        <option value="">-- Select --</option>
                        @foreach (var slot in availableSlots)
                        {
                            <option value="@slot">@slot</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => model.TimeSlot" />
                </div>

                <div class="mb-3">
                    <label for="reason" class="form-label">Reason for Visit</label>
                    <InputTextArea id="reason" class="form-control" @bind-Value="model.ReasonForVisit" rows="3" />
                    <ValidationMessage For="() => model.ReasonForVisit" />
                </div>

                <button type="button" class="btn btn-outline-secondary me-2" @onclick="BackToStep1">Back</button>
                <button type="button" class="btn btn-primary me-2" @onclick="CheckAvailability" disabled="@isChecking">
                    @(isChecking ? "Checking..." : "Check Availability")
                </button>
                @if (availabilityChecked)
                {
                    <button type="submit" class="btn btn-success">Confirm Appointment</button>
                }
            </fieldset>
        }
    </EditForm>
}

@code {
    private AppointmentFormModel model = new();
    private EditContext editContext = default!;
    private ValidationMessageStore messageStore = default!;

    private List<DoctorInfo> doctors = [];
    private List<string> availableSlots = [];

    private bool showStep2;
    private bool isChecking;
    private bool availabilityChecked;
    private bool isSubmitted;

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        messageStore = new ValidationMessageStore(editContext);
        editContext.OnFieldChanged += (_, args) =>
        {
            messageStore.Clear(args.FieldIdentifier);
            availabilityChecked = false;
        };

        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        messageStore.Clear();

        // Validate step 1 fields manually
        var step1Valid = true;

        if (string.IsNullOrWhiteSpace(model.PatientName))
        {
            messageStore.Add(() => model.PatientName, "Patient name is required.");
            step1Valid = false;
        }

        if (string.IsNullOrWhiteSpace(model.Email))
        {
            messageStore.Add(() => model.Email, "Email is required.");
            step1Valid = false;
        }
        else if (!IsValidEmail(model.Email))
        {
            messageStore.Add(() => model.Email, "Please enter a valid email address.");
            step1Valid = false;
        }

        if (string.IsNullOrWhiteSpace(model.Phone))
        {
            messageStore.Add(() => model.Phone, "Phone number is required.");
            step1Valid = false;
        }

        if (string.IsNullOrWhiteSpace(model.InsuranceProvider))
        {
            messageStore.Add(() => model.InsuranceProvider, "Please select an insurance provider.");
            step1Valid = false;
        }

        editContext.NotifyValidationStateChanged();

        if (step1Valid)
        {
            showStep2 = true;
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityChecked = false;
        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                model.Doctor, model.AppointmentDate.Value);
            model.TimeSlot = string.Empty;
        }
    }

    private async Task CheckAvailability()
    {
        messageStore.Clear();
        var step2Valid = true;

        if (string.IsNullOrWhiteSpace(model.Doctor))
        {
            messageStore.Add(() => model.Doctor, "Please select a doctor.");
            step2Valid = false;
        }

        if (!model.AppointmentDate.HasValue)
        {
            messageStore.Add(() => model.AppointmentDate, "Appointment date is required.");
            step2Valid = false;
        }
        else if (model.AppointmentDate.Value.Date <= DateTime.Today)
        {
            messageStore.Add(() => model.AppointmentDate, "Appointment date must be in the future.");
            step2Valid = false;
        }

        if (string.IsNullOrWhiteSpace(model.TimeSlot))
        {
            messageStore.Add(() => model.TimeSlot, "Please select a time slot.");
            step2Valid = false;
        }

        if (string.IsNullOrWhiteSpace(model.ReasonForVisit))
        {
            messageStore.Add(() => model.ReasonForVisit, "Reason for visit is required.");
            step2Valid = false;
        }
        else if (model.ReasonForVisit.Length > 500)
        {
            messageStore.Add(() => model.ReasonForVisit, "Reason for visit must be 500 characters or fewer.");
            step2Valid = false;
        }

        if (!step2Valid)
        {
            editContext.NotifyValidationStateChanged();
            return;
        }

        // Call server-side validation
        isChecking = true;

        try
        {
            var appointmentModel = ToServiceModel();
            var serverErrors = await AppointmentService.ValidatePatientAsync(appointmentModel);

            foreach (var (field, message) in serverErrors)
            {
                var fieldIdentifier = field switch
                {
                    nameof(AppointmentModel.Email) => editContext.Field(nameof(model.Email)),
                    nameof(AppointmentModel.Doctor) => editContext.Field(nameof(model.Doctor)),
                    nameof(AppointmentModel.TimeSlot) => editContext.Field(nameof(model.TimeSlot)),
                    _ => editContext.Field(field)
                };
                messageStore.Add(fieldIdentifier, message);
            }

            editContext.NotifyValidationStateChanged();
            availabilityChecked = serverErrors.Count == 0;
        }
        finally
        {
            isChecking = false;
        }
    }

    private async Task HandleSubmit()
    {
        if (!availabilityChecked) return;

        var appointmentModel = ToServiceModel();
        var success = await AppointmentService.SubmitAppointmentAsync(appointmentModel);

        if (success)
        {
            isSubmitted = true;
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        availabilityChecked = false;
        messageStore.Clear();
        editContext.NotifyValidationStateChanged();
    }

    private AppointmentModel ToServiceModel() => new()
    {
        PatientName = model.PatientName,
        Email = model.Email,
        Phone = model.Phone,
        InsuranceProvider = model.InsuranceProvider,
        Doctor = model.Doctor,
        AppointmentDate = model.AppointmentDate,
        TimeSlot = model.TimeSlot,
        ReasonForVisit = model.ReasonForVisit
    };

    private static bool IsValidEmail(string email)
    {
        try
        {
            var addr = new System.Net.Mail.MailAddress(email);
            return addr.Address == email;
        }
        catch
        {
            return false;
        }
    }

    // Separate form model so DataAnnotations and ValidationMessageStore work on the EditContext.
    private sealed class AppointmentFormModel
    {
        public string PatientName { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
        public string InsuranceProvider { get; set; } = string.Empty;
        public string Doctor { get; set; } = string.Empty;
        public DateTime? AppointmentDate { get; set; }
        public string TimeSlot { get; set; } = string.Empty;
        public string ReasonForVisit { get; set; } = string.Empty;
    }
}

