+            messageStore.Add(() => model.ReasonForVisit, "Reason for visit is required.");
+            step2Valid = false;
+        }
+        else if (model.ReasonForVisit.Length > 500)
+        {
+            messageStore.Add(() => model.ReasonForVisit, "Reason for visit must be 500 characters or fewer.");
+            step2Valid = false;
+        }
+
+        if (!step2Valid)
+        {
+            editContext.NotifyValidationStateChanged();
+            return;
+        }
+
+        // Call server-side validation
+        isChecking = true;
+
+        try
+        {
+            var appointmentModel = ToServiceModel();
+            var serverErrors = await AppointmentService.ValidatePatientAsync(appointmentModel);
+
+            foreach (var (field, message) in serverErrors)
+            {
+                var fieldIdentifier = field switch
+                {
+                    nameof(AppointmentModel.Email) => editContext.Field(nameof(model.Email)),
+                    nameof(AppointmentModel.Doctor) => editContext.Field(nameof(model.Doctor)),
+                    nameof(AppointmentModel.TimeSlot) => editContext.Field(nameof(model.TimeSlot)),
+                    _ => editContext.Field(field)
+                };
+                messageStore.Add(fieldIdentifier, message);
+            }
+
+            editContext.NotifyValidationStateChanged();
+            availabilityChecked = serverErrors.Count == 0;
+        }
+        finally
+        {
+            isChecking = false;
+        }
+    }
+
+    private async Task HandleSubmit()
+    {
+        if (!availabilityChecked) return;
+
+        var appointmentModel = ToServiceModel();
+        var success = await AppointmentService.SubmitAppointmentAsync(appointmentModel);
+
+        if (success)
+        {
+            isSubmitted = true;
+        }
+    }
+
+    private void BackToStep1()
+    {
+        showStep2 = false;
+        availabilityChecked = false;
+        messageStore.Clear();
+        editContext.NotifyValidationStateChanged();
+    }
+
+    private AppointmentModel ToServiceModel() => new()
+    {
+        PatientName = model.PatientName,
+        Email = model.Email,
+        Phone = model.Phone,
+        InsuranceProvider = model.InsuranceProvider,
+        Doctor = model.Doctor,
+        AppointmentDate = model.AppointmentDate,
+        TimeSlot = model.TimeSlot,
+        ReasonForVisit = model.ReasonForVisit
+    };
+
+    private static bool IsValidEmail(string email)
+    {
+        try
+        {
+            var addr = new System.Net.Mail.MailAddress(email);
+            return addr.Address == email;
+        }
+        catch
+        {
+            return false;
+        }
+    }
+
+    // Separate form model so DataAnnotations and ValidationMessageStore work on the EditContext.
+    private sealed class AppointmentFormModel
+    {
+        public string PatientName { get; set; } = string.Empty;
+        public string Email { get; set; } = string.Empty;
+        public string Phone { get; set; } = string.Empty;
+        public string InsuranceProvider { get; set; } = string.Empty;
+        public string Doctor { get; set; } = string.Empty;
+        public DateTime? AppointmentDate { get; set; }
+        public string TimeSlot { get; set; } = string.Empty;
+        public string ReasonForVisit { get; set; } = string.Empty;
+    }
+}
