namespace sv_392bf44bdbc4411a967ecaccbde3178c.Services;

public class DoctorInfo
{
    public string Name { get; set; } = string.Empty;
    public bool AcceptsSelfPay { get; set; }
}

public class AppointmentModel
{
    // Step 1
    public string PatientName { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
    public string InsuranceProvider { get; set; } = string.Empty;

    // Step 2
    public string Doctor { get; set; } = string.Empty;
    public DateTime? AppointmentDate { get; set; }
    public string TimeSlot { get; set; } = string.Empty;
    public string ReasonForVisit { get; set; } = string.Empty;
}

public interface IAppointmentService
{
    Task<List<DoctorInfo>> GetDoctorsAsync();
    Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateTime date);
    Task<Dictionary<string, string>> ValidatePatientAsync(AppointmentModel model);
    Task<bool> SubmitAppointmentAsync(AppointmentModel model);
}

public class AppointmentService : IAppointmentService
{
    private static readonly List<DoctorInfo> Doctors =
    [
        new() { Name = "Dr. Smith", AcceptsSelfPay = false },
        new() { Name = "Dr. Johnson", AcceptsSelfPay = true },
        new() { Name = "Dr. Williams", AcceptsSelfPay = true },
        new() { Name = "Dr. Brown", AcceptsSelfPay = false },
    ];

    public Task<List<DoctorInfo>> GetDoctorsAsync()
    {
        return Task.FromResult(Doctors);
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateTime date)
    {
        List<string> slots = ["9:00 AM", "10:00 AM", "11:00 AM", "1:00 PM", "2:00 PM", "3:00 PM"];
        return Task.FromResult(slots);
    }

    public Task<Dictionary<string, string>> ValidatePatientAsync(AppointmentModel model)
    {
        var errors = new Dictionary<string, string>();

        // Simulate outstanding balance check
        if (string.Equals(model.Email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(model.Email)] = "Account has outstanding balance";
        }

        // Simulate self-pay rejection
        if (model.InsuranceProvider == "None")
        {
            var doctor = Doctors.Find(d => d.Name == model.Doctor);
            if (doctor is { AcceptsSelfPay: false })
            {
                errors[nameof(model.Doctor)] = "Selected doctor does not accept self-pay patients";
            }
        }

        // Simulate race condition on time slot
        if (model.TimeSlot == "10:00 AM")
        {
            errors[nameof(model.TimeSlot)] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }

    public Task<bool> SubmitAppointmentAsync(AppointmentModel model)
    {
        return Task.FromResult(true);
    }
}

